rule AntiDebug_APIs
{
    meta:
        description = "Detects common anti-debugging API calls"
        author = "Analyst"
        date = "2025-01-01"
    strings:
        // IsDebuggerPresent (kernel32)
        $idp1 = "IsDebuggerPresent" ascii wide nocase
        // NtQueryInformationProcess (ntdll)
        $nqip1 = "NtQueryInformationProcess" ascii wide nocase
        // CheckRemoteDebuggerPresent (kernel32)
        $crdp1 = "CheckRemoteDebuggerPresent" ascii wide nocase
        // OutputDebugString (kernel32) - 用于检测调试器
        $ods1 = "OutputDebugString" ascii wide nocase
        // 直接读取PEB (mov eax, fs:[30h])
        $peb1 = { 64 A1 30 00 00 00 }  // mov eax, fs:[0x30]  (x86)
        $peb2 = { 65 48 8B 04 25 60 00 00 00 }  // mov rax, gs:[0x60] (x64)
        // 检查PEB.BeingDebugged (偏移0x2)
        $being_debugged = { 80 78 02 00 }  // cmp byte ptr [eax+2], 0
        // NtSetInformationThread (隐藏线程)
        $nsit1 = "NtSetInformationThread" ascii wide nocase
        // ZwQueryInformationProcess (ntdll)
        $zqip1 = "ZwQueryInformationProcess" ascii wide nocase
    condition:
        // 至少匹配两个不同的反调试特征
        (#idp1 + #nqip1 + #crdp1 + #ods1 + #peb1 + #peb2 + #being_debugged + #nsit1 + #zqip1) >= 2
}

rule AntiDebug_Timing
{
    meta:
        description = "Detects timing-based anti-debug (e.g., rdtsc)"
    strings:
        // RDTSC指令
        $rdtsc = { 0F 31 }  // rdtsc
        // GetTickCount
        $gtc1 = "GetTickCount" ascii wide nocase
        // QueryPerformanceCounter
        $qpc1 = "QueryPerformanceCounter" ascii wide nocase
    condition:
        1 of ($rdtsc, $gtc*, $qpc*)
}


