PE文件的资源节（.rsrc）采用三层树状结构：类型（Type）、名称（Name）、语言（Language）。每个节点是一个IMAGE_RESOURCE_DIRECTORY，包含多个目录条目。最终叶子节点指向IMAGE_RESOURCE_DATA_ENTRY，包含资源数据的RVA和大小。常见资源类型包括：RT_ICON（3）、RT_STRING（6）、RT_RCDATA（10）等。

以下Python代码使用pefile提取所有字符串资源（RT_STRING）：

python
import pefile

def extract_string_resources(filepath):
    pe = pefile.PE(filepath)
    strings = []
    if hasattr(pe, 'DIRECTORY_ENTRY_RESOURCE'):
        for resource_type in pe.DIRECTORY_ENTRY_RESOURCE.entries:
            if resource_type.name is not None and resource_type.name.string == "RT_STRING":
                # 遍历名称和语言
                for resource_name in resource_type.directory.entries:
                    for resource_lang in resource_name.directory.entries:
                        data_rva = resource_lang.data.struct.OffsetToData
                        size = resource_lang.data.struct.Size
                        data = pe.get_data(data_rva, size)
                        # RT_STRING格式：每个字符串前有长度（2字节），后跟Unicode字符
                        offset = 0
                        while offset < len(data):
                            if offset + 2 > len(data):
                                break
                            length = struct.unpack('<H', data[offset:offset+2])[0]
                            offset += 2
                            if length > 0 and offset + length*2 <= len(data):
                                try:
                                    s = data[offset:offset+length*2].decode('utf-16-le')
                                    strings.append(s)
                                except:
                                    pass
                                offset += length*2
                            else:
                                break
    return strings

# 示例
strings = extract_string_resources("malware.exe")
for s in strings:
    print(s)


