import pefile

def parse_imports_and_exports(filepath):
    pe = pefile.PE(filepath)
    # 解析导入表
    print("=== Import Table ===")
    if hasattr(pe, 'DIRECTORY_ENTRY_IMPORT'):
        for entry in pe.DIRECTORY_ENTRY_IMPORT:
            dll_name = entry.dll.decode('utf-8', errors='ignore')
            print(f"DLL: {dll_name}")
            for imp in entry.imports:
                if imp.name:
                    func_name = imp.name.decode('utf-8', errors='ignore')
                else:
                    func_name = f"Ordinal: {imp.ordinal}"
                print(f"  {func_name} (RVA: 0x{imp.address:08X})")
    else:
        print("No import table found.")

    # 解析导出表
    print("\n=== Export Table ===")
    if hasattr(pe, 'DIRECTORY_ENTRY_EXPORT'):
        export = pe.DIRECTORY_ENTRY_EXPORT
        print(f"DLL Name: {export.name.decode('utf-8', errors='ignore')}")
        print(f"Base Ordinal: {export.struct.Base}")
        print(f"Number of Functions: {export.struct.NumberOfFunctions}")
        print(f"Number of Names: {export.struct.NumberOfNames}")
        for exp in export.symbols:
            if exp.name:
                func_name = exp.name.decode('utf-8', errors='ignore')
            else:
                func_name = f"Ordinal: {exp.ordinal}"
            print(f"  {func_name} (RVA: 0x{exp.address:08X})")
    else:
        print("No export table found.")
    pe.close()

if __name__ == "__main__":
    parse_imports_and_exports("sample.dll")  # 也可用于EXE


